def get_nome_segno(gradi):
    segni = [
        "Ariete", "Toro", "Gemelli", "Cancro", "Leone", "Vergine",
        "Bilancia", "Scorpione", "Sagittario", "Capricorno", "Acquario", "Pesci"
    ]
    indice_segno = int(gradi // 30)
    if indice_segno >= len(segni):
        indice_segno = 0
    return segni[indice_segno]

