class TransitoGiornaliero:
    def __init__(self, data, pianeta_transito, grado_transito,
                 pianeta_natale, aspetto, orbita, casa_natale, segno_natale,
                 fascia_oraria="", ora_esatta=0):
        self.data = data
        self.pianeta_transito = pianeta_transito
        self.grado_transito = grado_transito
        self.pianeta_natale = pianeta_natale
        self.aspetto = aspetto
        self.orbita = orbita
        self.casa_natale = casa_natale
        self.segno_natale = segno_natale
        self.fascia_oraria = fascia_oraria
        self.ora_esatta = ora_esatta
        self.ora = ora_esatta  # <-- USA L'ORA ESATTA
        self.importanza = self._calcola_importanza()
    
    def _calcola_importanza(self):
        peso_aspetto = {
            'CONGIUNZIONE': 10, 'OPPOSIZIONE': 9, 'QUADRATURA': 8,
            'TRIGONO': 7, 'SESTILE': 5, 'QUINCONCE': 4,
            'SESQUIQUADRATO': 3, 'SEMIQUADRATO': 2, 'SEMISESTILE': 1
        }.get(self.aspetto, 5)
        pianeti_personali = ['Sole', 'Luna', 'Mercurio', 'Venere', 'Marte']
        bonus = 2 if self.pianeta_transito in pianeti_personali else 0
        return max(1, min(10, round(peso_aspetto + bonus)))
    
    def _estrai_ora(self, fascia_oraria):
        match = re.search(r'(\d{2}):(\d{2})', fascia_oraria)
        if match:
            ore = int(match.group(1))
            minuti = int(match.group(2))
            return ore + minuti/60
        return 0


