    def get_segno_da_grado(self, grado):
        """Restituisce il segno zodiacale dato un grado (0-360)"""
        segni = ['Ariete', 'Toro', 'Gemelli', 'Cancro', 'Leone', 'Vergine',
                 'Bilancia', 'Scorpione', 'Sagittario', 'Capricorno', 'Acquario', 'Pesci']
        indice = int(grado // 30)
        if indice >= len(segni):
            indice = 0
        return segni[indice]

    def calcola_posizioni_giorno(self, data, ora="12:00", fuso="Europe/Rome"):
        """Calcola le posizioni dei pianeti a una data e ora specifica"""
        if isinstance(data, str):
            if '/' in data:
                gg, mm, aaaa = data.split('/')
                data_iso = f"{aaaa}-{mm}-{gg}"
            else:
                data_iso = data
        else:
            data_iso = data.strftime('%Y-%m-%d')
        
        anno, mese, giorno = map(int, data_iso.split('-'))
        ora_int, min_int = map(int, ora.split(':'))
        
        try:
            dt_naive = datetime(anno, mese, giorno, ora_int, min_int)
        except ValueError:
            print(f"⚠️ Data non valida: {anno}-{mese:02d}-{giorno:02d}, uso ultimo giorno del mese")
            if mese == 12:
                mese = 1
                anno += 1
            else:
                mese += 1
            dt_naive = datetime(anno, mese, 1, ora_int, min_int) - timedelta(days=1)
        
        timezone = pytz.timezone(fuso)
        dt_local = timezone.localize(dt_naive)
        dt_utc = dt_local.astimezone(pytz.UTC)
        
        ora_utc = dt_utc.hour + dt_utc.minute/60.0
        julday_utc = swe.julday(dt_utc.year, dt_utc.month, dt_utc.day, ora_utc)
        
        posizioni = {}
        for nome, id_pianeta in self.pianeti_ids.items():
            pos = swe.calc_ut(julday_utc, id_pianeta)[0]
            posizioni[nome] = pos[0]
        
        return posizioni

    def trova_aspetto_transito(self, diff):
        """Trova l'aspetto per i transiti con orbita 0.5°"""
        for nome_aspetto, gradi_ideali in ASPETTI_TRANSITI.items():
            if abs(diff - gradi_ideali) <= 0.5:
                return nome_aspetto
        return None

    def trova_aspetto(self, diff):
        """Trova l'aspetto con orbita più ampia (7°)"""
        orbite = {
            'CONGIUNZIONE': (0, 8), 'SESTILE': (60, 6), 'QUADRATURA': (90, 7),
            'TRIGONO': (120, 8), 'SESQUIQUADRATO': (135, 3), 'OPPOSIZIONE': (180, 8)
        }
        for aspetto, (gradi, orbita) in orbite.items():
            if abs(diff - gradi) <= orbita:
                return aspetto
        return None

    def _peso_aspetto(self, aspetto):
        """Restituisce il peso di un aspetto"""
        pesi = {
            'CONGIUNZIONE': 5, 'SESTILE': 2, 'TRIGONO': 3,
            'QUADRATURA': -3, 'OPPOSIZIONE': -3, 'SESQUIQUADRATO': -1
        }
        return pesi.get(aspetto, 0)

    # ------------------------------------------------------------
    # FUNZIONI PER I TRANSITI DELLA LUNA
    # ------------------------------------------------------------

    def calcola_transiti_giornalieri(self, data_transito, fuso="Europe/Rome"):
        """
        Calcola i transiti della Luna ogni 5 minuti per tutto il giorno
        MOSTRA L'ORA UTC (GREENWICH) NELL'OUTPUT
        """
        from datetime import datetime, timedelta
        import pytz
        
        print(f"🔴 CALCOLO TRANSITI LUNA per {data_transito} 🔴")
        
        # Set per evitare duplicati
        aspetti_visti = set()
        aspetti_cuspidi_visti = set()
        ultima_casa_luna = None
        
        tutti_transiti = []
        
        # Imposta inizio giornata in UTC
        inizio_giorno_utc = datetime.strptime(f"{data_transito} 00:00", "%Y-%m-%d %H:%M")
        
        for minuti in range(0, 24*60, 5):
            # Ora UTC
            momento_utc = inizio_giorno_utc + timedelta(minutes=minuti)
            
            # 🔴 USO L'ORA UTC PER LA VISUALIZZAZIONE (NON CONVERTO IN LOCALE)
            ora_str = momento_utc.strftime("%H:%M")
            ore_utc = momento_utc.hour + momento_utc.minute / 60
            
            # Calcola posizioni usando l'ora UTC
            posizioni = self.calcola_posizioni_giorno(data_transito, ora_str, fuso)
            grado_luna = posizioni['Luna']
            
            # ============================================
            # 1. LUNA NELLA CASA
            # ============================================
            casa_luna = pianeta_in_casa(grado_luna, self.dati_natali['cusps'])
            if ultima_casa_luna != casa_luna:
                tutti_transiti.append(TransitoGiornaliero(
                    data_transito, 'Luna', grado_luna,
                    f"Casa {casa_luna}", 'TRANSITO', 0, casa_luna,
                    get_nome_segno(grado_luna), ora_in_fascia(ore_utc), ore_utc
                ))
                ultima_casa_luna = casa_luna
            
            # ============================================
            # 2. LUNA CON PIANETI NATALI
            # ============================================
            for pianeta, grado_natale in self.dati_natali['posizioni'].items():
                diff = abs(grado_luna - grado_natale)
                if diff > 180:
                    diff = 360 - diff
                
                if abs(diff - 0) <= 0.05:
                    aspetto = 'CONGIUNZIONE'
                elif abs(diff - 60) <= 0.05:
                    aspetto = 'SESTILE'
                elif abs(diff - 90) <= 0.05:
                    aspetto = 'QUADRATURA'
                elif abs(diff - 120) <= 0.05:
                    aspetto = 'TRIGONO'
                elif abs(diff - 180) <= 0.05:
                    aspetto = 'OPPOSIZIONE'
                else:
                    continue
                
                chiave = f"Luna_{pianeta}_{aspetto}"
                if chiave not in aspetti_visti:
                    tutti_transiti.append(TransitoGiornaliero(
                        data_transito, 'Luna', grado_luna,
                        pianeta, aspetto, diff,
                        casa_luna, get_nome_segno(grado_natale),
                        ora_in_fascia(ore_utc), ore_utc
                    ))
                    aspetti_visti.add(chiave)
            
            # ============================================
            # 3. LUNA CON CUSPIDI
            # ============================================
            nomi_cuspidi = ['Ascendente', 'II', 'III', 'FC', 'V', 'VI', 
                            'Discendente', 'VIII', 'IX', 'MC', 'XI', 'XII']
            
            for idx, grado_cuspide in enumerate(self.dati_natali['cusps']):
                diff = abs(grado_luna - grado_cuspide)
                if diff > 180:
                    diff = 360 - diff
                
                if abs(diff - 0) <= 0.05:
                    aspetto = 'CONGIUNZIONE'
                elif abs(diff - 60) <= 0.05:
                    aspetto = 'SESTILE'
                elif abs(diff - 90) <= 0.05:
                    aspetto = 'QUADRATURA'
                elif abs(diff - 120) <= 0.05:
                    aspetto = 'TRIGONO'
                elif abs(diff - 180) <= 0.05:
                    aspetto = 'OPPOSIZIONE'
                else:
                    continue
                
                chiave = f"Luna_{nomi_cuspidi[idx]}_{aspetto}"
                if chiave not in aspetti_cuspidi_visti:
                    numero_casa = idx + 1
                    tutti_transiti.append(TransitoGiornaliero(
                        data_transito, 'Luna', grado_luna,
                        nomi_cuspidi[idx], aspetto, diff,
                        numero_casa, get_nome_segno(grado_cuspide),
                        ora_in_fascia(ore_utc), ore_utc
                    ))
                    aspetti_cuspidi_visti.add(chiave)
        
        print(f"✅ Trovati {len(tutti_transiti)} transiti lunari")
        return tutti_transiti
    
    def calcola_transiti_pianeti_giornalieri(self, data_transito, fuso="Europe/Rome"):
        """
        Calcola i transiti SINGOLI di tutti i pianeti (esclusa Luna)
        Su ogni punto radix (pianeti natali e cuspidi)
        MOSTRA L'ORA UTC (GREENWICH) NELL'OUTPUT
        """
        from datetime import datetime, timedelta
        import pytz
        
        print(f"🔴 CALCOLO TRANSITI SINGOLI PIANETI per {data_transito} 🔴")
        
