    def genera_report_giornaliero(self, cluster):
        """Genera un report descrittivo per l'utente con raggruppamento per fasce"""
        if not cluster:
            return "🌙 Oggi non ci sono momenti particolarmente significativi."
        
        # Raggruppa per fascia oraria (ogni 2 ore)
        fascie = {
            '00-02': {'inizio': 0, 'fine': 2, 'eventi': []},
            '02-04': {'inizio': 2, 'fine': 4, 'eventi': []},
            '04-06': {'inizio': 4, 'fine': 6, 'eventi': []},
            '06-08': {'inizio': 6, 'fine': 8, 'eventi': []},
            '08-10': {'inizio': 8, 'fine': 10, 'eventi': []},
            '10-12': {'inizio': 10, 'fine': 12, 'eventi': []},
            '12-14': {'inizio': 12, 'fine': 14, 'eventi': []},
            '14-16': {'inizio': 14, 'fine': 16, 'eventi': []},
            '16-18': {'inizio': 16, 'fine': 18, 'eventi': []},
            '18-20': {'inizio': 18, 'fine': 20, 'eventi': []},
            '20-22': {'inizio': 20, 'fine': 22, 'eventi': []},
            '22-24': {'inizio': 22, 'fine': 24, 'eventi': []}
        }
        
        for c in cluster:
            ora = c['ora']
            for fascia, dati in fascie.items():
                if dati['inizio'] <= ora < dati['fine']:
                    dati['eventi'].append(c)
                    break
        
        # Mappa descrittiva per i pianeti
        descrizioni_pianeti = {
            'Sole': 'identità, vitalità',
            'Luna': 'emozioni, sensibilità',
            'Mercurio': 'comunicazione, pensiero',
            'Venere': 'amore, relazioni',
            'Marte': 'energia, azione',
            'Giove': 'espansione, fortuna',
            'Saturno': 'responsabilità, disciplina',
            'Urano': 'cambiamento, libertà',
            'Nettuno': 'intuizione, sogni',
            'Plutone': 'trasformazione, potere'
        }
        
        descrizioni_case = {
            'Ascendente': 'la tua immagine',
            'II': 'le tue risorse',
            'III': 'la comunicazione',
            'FC': 'le tue radici',
            'V': 'la creatività',
            'VI': 'il lavoro, la salute',
            'Discendente': 'le relazioni',
            'VIII': 'le trasformazioni',
            'IX': 'i viaggi, gli studi',
            'MC': 'la carriera',
            'XI': 'le amicizie',
            'XII': 'la spiritualità'
        }
        
        report = "🌅 BUONGIORNO! Ecco i momenti chiave della giornata:\n\n"
        
        for fascia, dati in fascie.items():
            if not dati['eventi']:
                continue
            
            # Analizza gli eventi della fascia
            tipi = [e['tipo_cluster'] for e in dati['eventi']]
            if 'armonico' in tipi and 'disarmonico' in tipi:
                emoji_fascia = "🔄"
                effetto_fascia = "alternato"
            elif 'armonico' in tipi:
                emoji_fascia = "✨"
                effetto_fascia = "positivo"
            else:
                emoji_fascia = "⚠️"
                effetto_fascia = "teso"
            
            # Raccogli tutti i punti radix attivati in questa fascia
            radix_attivati = list(set(e['radix'] for e in dati['eventi']))
            
            # Converti in descrizioni
            aree = []
            for r in radix_attivati:
                if r in descrizioni_case:
                    aree.append(descrizioni_case[r])
                elif r in descrizioni_pianeti:
                    aree.append(f"il tuo {r} ({descrizioni_pianeti[r]})")
                else:
                    aree.append(f"il tuo {r}")
            
            if len(aree) == 1:
                area_testo = aree[0]
            elif len(aree) == 2:
                area_testo = f"{aree[0]} e {aree[1]}"
            else:
                area_testo = ", ".join(aree[:-1]) + f" e {aree[-1]}"
            
            # Trova l'ora più significativa della fascia
            ore_significative = sorted([e['ora'] for e in dati['eventi']])
            ora_media = sum(ore_significative) / len(ore_significative)
            ore = int(ora_media)
            minuti = int((ora_media - ore) * 60)
            ora_str = f"{ore:02d}:{minuti:02d}"
            
            report += f"{emoji_fascia} **Tra le {dati['inizio']:02d}:00 e le {dati['fine']:02d}:00** (momento chiave alle {ora_str})\n"
            report += f"   Periodo {effetto_fascia} per {area_testo}.\n"
            
            # Suggerimento in base al tipo prevalente
            if 'armonico' in tipi and 'disarmonico' not in tipi:
                report += "   ✨ Approfitta per azioni importanti in queste aree.\n"
            elif 'disarmonico' in tipi and 'armonico' not in tipi:
                report += "   ⚠ Meglio evitare decisioni importanti in queste aree.\n"
            else:
                report += "   🔄 Momenti alternati: ascolta il tuo intuito.\n"
            report += "\n"
        
        return report
    
    def genera_messaggio_confortevole(self, transito):
        """Genera un messaggio confortevole e di supporto per il transito"""
        
        # PROTEZIONE
        if transito is None:
            return None
        
        if not hasattr(transito, 'pianeta_natale') or transito.pianeta_natale is None:
            return None
        
        if not isinstance(transito.pianeta_natale, str):
            return None
        
        msg_data = None
        
        # ============================================
        # 1. TRANSITI IN CASA (pianeta dentro una casa)
        # ============================================
        if transito.aspetto == 'TRANSITO' and transito.pianeta_natale.startswith('Casa'):
            try:
                numero_casa = int(transito.pianeta_natale.replace('Casa ', ''))
                msg_data = MESSAGGI_TRANSITI.get(f'{transito.pianeta_transito.lower()}_in_casa', {}).get(numero_casa)
            except (ValueError, AttributeError):
                pass
        
        # ============================================
        # 2. CUSPIDI (aspetti con Ascendente, MC, II, III, ecc.)
        # ============================================
        elif transito.pianeta_natale in CUSPIDE_TO_CASA:
            numero_casa = CUSPIDE_TO_CASA[transito.pianeta_natale]
            # Cerca messaggio specifico per pianeta_cuspide
            msg_data = MESSAGGI_TRANSITI.get(f'{transito.pianeta_transito.lower()}_{transito.pianeta_natale.lower()}', {}).get(transito.aspetto.lower())
        
        # ============================================
        # 3. ASPETTI CON PIANETI (per TUTTI i pianeti in transito)
        # ============================================
        else:
            
            chiave = f"{transito.pianeta_transito.lower()}_{transito.pianeta_natale.lower()}"
            print(f"🔍 Cerco chiave: {chiave} per {transito.pianeta_transito} - {transito.aspetto} - {transito.pianeta_natale}")
            msg_data = MESSAGGI_TRANSITI.get(chiave, {}).get(transito.aspetto.lower())
        
        # ============================================
        # 4. SE NON TROVATO, CERCA MESSAGGIO GENERICO
        # ============================================
        if not msg_data:
            msg_data = MESSAGGI_TRANSITI.get(f'{transito.pianeta_transito.lower()}_generico', {}).get(transito.aspetto.lower())
        
        if not msg_data:
            print(f"❌ NESSUN MESSAGGIO per: {transito.pianeta_transito} - {transito.aspetto} - {transito.pianeta_natale}")
            return None
        
        # Emoji in base all'aspetto
        emoji_aspetto = {
            'congiunzione': '🌕', 'sestile': '🌸', 'quadratura': '⚡',
            'trigono': '✨', 'opposizione': '🌑', 'sesquiquadrato': '🔶',
            'transito': '💫'
        }.get(transito.aspetto.lower(), '💫')
        
        titolo = f"{emoji_aspetto} {msg_data['titolo']}"
        
        print(f"✅ TROVATO: {titolo}")
        
        return f"""
        💖 {titolo}

        {msg_data['messaggio']}

        💡 CONSIGLIO DEL GIORNO:
        {msg_data['consiglio']}
        """
    def genera_messaggio_tecnico(self, transito):
        """Genera un messaggio tecnico per il transito"""
        
        # Protezione
        if transito is None:
            return "Dati transito non disponibili"
        
        # Cerca nel dizionario dei messaggi (usa self.messaggi, NON self.MESSAGGI)
        msg_dict = self.messaggi.get(transito.pianeta_transito, {})
        template = msg_dict.get(transito.aspetto, self.messaggio_generico)
        
        return template.format(
            pianeta_transito=transito.pianeta_transito,
            pianeta_natale=transito.pianeta_natale,
            aspetto=transito.aspetto.lower(),
            casa=interpreta_casa(transito.casa_natale).lower()
        )
    
    def _dura_tutto_il_giorno(self, transito, tutti_transiti):
        """Verifica se un transito in casa dura tutto il giorno"""
        # Cerca altri transiti della stessa casa con orari diversi
        stesso_tipo = [t for t in tutti_transiti 
                    if t.pianeta_natale == transito.pianeta_natale 
                    and t.aspetto == transito.aspetto]
        
        # Se ci sono più transiti dello stesso tipo, non dura tutto il giorno
        if len(stesso_tipo) > 1:
            return False
        
        # Altrimenti, controlla se l'ora è intorno a mezzanotte
        ore = int(transito.ora)
        return ore == 0 or ore == 23

    def analizza_giornata_completa(self, data_transito, fuso="Europe/Rome"):
        """
        Analisi completa della giornata:
        1. Trova tutti gli aspetti tra pianeti in transito
        2. Calcola i punti medi di energia
        3. Verifica quali punti radix vengono attivati
        """
        risultati = {
            'aspetti_tra_transiti': [],
            'punti_medi': [],
            'attivazioni_radix': [],
            'momento_massima_energia': None
        }
        
        # Analizza ogni 5 minuti
        for minuti in range(0, 24*60, 5):
            ore = minuti / 60
            ore_str = f"{int(ore):02d}:{int((ore%1)*60):02d}"
            posizioni = self.calcola_posizioni_giorno(data_transito, ore_str, fuso)
            
            # 1. Trova tutti gli aspetti tra pianeti in transito
            aspetti_ora = []
            pianeti_lista = list(posizioni.keys())
            
            for i, p1 in enumerate(pianeti_lista):
                for p2 in pianeti_lista[i+1:]:
                    diff = abs(posizioni[p1] - posizioni[p2])
                    if diff > 180: diff = 360 - diff
                    
                    aspetto = self.trova_aspetto(diff)
                    if aspetto:
                        aspetti_ora.append({
                            'p1': p1, 'p2': p2,
                            'grado1': posizioni[p1],
                            'grado2': posizioni[p2],
                            'aspetto': aspetto,
                            'ora': ore
                        })
            
            # 2. Raggruppa per configurazioni (es. stelle, opposizioni, ecc.)
            if len(aspetti_ora) >= 2:
                # Calcola punti medi
                for i, asp1 in enumerate(aspetti_ora):
                    for asp2 in aspetti_ora[i+1:]:
                        punto_medio = self.calcola_punto_medio(asp1, asp2)
                        
                        # 3. Verifica attivazioni radix
                        for nome_radix, grado_radix in self.dati_natali['posizioni'].items():
                            diff = abs(punto_medio - grado_radix)
                            if diff <= 1:  # orbita stretta
                                risultati['attivazioni_radix'].append({
                                    'ora': ore,
                                    'punto_medio': punto_medio,
                                    'radix': nome_radix,
                                    'configurazione': (asp1, asp2)
                                })
        
        return risultati

 